sys_script_fix.script:
const ds_sys_id = "1f5e18a8c3044310c134bf12b4013136"; // Model data source, attachment lives here
var gr_att = new GlideRecord("sys_attachment");
gr_att.addQuery("table_name", "sys_data_source");
gr_att.addQuery("table_sys_id", ds_sys_id);
gr_att.setLimit(1);
gr_att.query();
gr_att.next();
var parser = new x_42999_decision_0.BaseParser();
var objects = parser.getEntries(gr_att, parser.DEFAULT_HELPER.bind(parser));
gs.info(JSON.stringify(objects, null, 2));
